function BadgeIcon:ResetIcon()
	BaseIconNew.ResetIcon(self)

	self._refId = 0
	self._num = nil
	self._star = 0
	self._showGou = false
	self._showNum = false
	self._showLv = false
end

-----------------------------------------------------------------
function BadgeIcon:ApplyIconUI()
	BaseIconNew.ApplyIconUI(self)

	self:SetIcon(self._displayShowIcon)
	self:SetIconBg(self._displayShowIconBg)

	local refId = self._refId
	local showStar = refId and refId > 0
	if showStar then
		self:UpdateStarUI()
	end
	CS.ShowObject(self._uiStarTrans, showStar)

	self:SetGouTransVisible(self._showGou)
	self:ShowMask(self._showGou)
	self:SetEquipIconGray()

	self:SetNumUIVisible()
	self:SetLvUIVisible()
	self:UpdateLimitedImage()
	self:ApplyNumTxt()
	self:ApplyLvTxt()

	if self._refId then
		local ref = GameTable.BadgeRef[self._refId]
		local path = self.skillTypeImg[ref.skillType]
		self._ownerWndClass:SetWndEasyImage(self._uiSkillType,path)
	end
end

function BadgeIcon:OnInitTrans()

	local iconInst = self._iconInst
	self._uiNumTxtTrans = CS.FindTrans(iconInst,"NumTxt")
	self._uiLvTxtTrans = CS.FindTrans(iconInst,"LvTxt")
	self._uiGouTrans = CS.FindTrans(iconInst,"GouImg")
	self._uiStarTrans = CS.FindTrans(iconInst, "StarList")
	self:InitStartList()
	self._uiMaskTrans = CS.FindTrans(iconInst,"ImgMask")
	self._uiSkillType = CS.FindTrans(iconInst,"SkillType")
	self._uiLimited = CS.FindTrans(iconInst,"Limited")
end

-----------------------------------------------------------------
function BadgeIcon:EnableShowNum(bShow)
	self._showNum = bShow
	self:UpdateNumData()
end

function BadgeIcon:ShowNum(b)
	self._showNum = b

	self:UpdateNumData()

	if not self:IsIconValid() then return end

	self:SetNumUIVisible()

end

function BadgeIcon:UpdateNumData()
	if self._showNum and not self._num then
		self._displayNum = 0--num or 0
		return
	end

	self._displayNum = self._num or 0

end

function BadgeIcon:SetNumUIVisible()
	local b = self._showNum and self._showNum or false

	if self._uiNumTxtTrans.gameObject.activeSelf ~= b then
		CS.ShowObject(self._uiNumTxtTrans, b)
	end
end

function BadgeIcon:ApplyNumTxt()
	if not self._showNum then return end
	local num = self._displayNum
	local numStr = tostring(num)
	if not num or num == -1 then
		numStr = ""
	end
	self:SetXUIText(self._uiNumTxtTrans,numStr)
end

function BadgeIcon:SetNoShowLv(b)
	if self._showLv == b then
		return
	end
	self._showLv = b
	if not self:IsIconValid() then
		return
	end
	self:SetLvUIVisible(not b)
end

function BadgeIcon:SetLvUIVisible()
	if self._uiLvTxtTrans and self._uiLvTxtTrans.gameObject.activeSelf ~= self._showLv then
		CS.ShowObject(self._uiLvTxtTrans, self._showLv)
	end
end

function BadgeIcon:ApplyLvTxt()
	if self._uiLvTxtTrans then
		local lvColor, lvMat = LUtil.GetResonanceColor()
		lvColor = LUtil.ColorByHex(lvColor)
		self:SetXUIText(self._uiLvTxtTrans, self._lvTxtStr or "", nil, lvColor)
		if lvMat then
			self:SetWndTextMat(self._uiLvTxtTrans, lvMat)
		end
	end
end


function BadgeIcon:SetItemNum(num)
	self._num = num

	self:UpdateNumData()

	if not self:IsIconValid() then return end
	self:ApplyNumTxt()
end

function BadgeIcon:SetItemlv(num)
	self._lvTxtStr = num

	if not self:IsIconValid() then return end
	self:ApplyLvTxt()()
end


function BadgeIcon:SetShowGouImg(b)
	b = b or false and true
	self._showGou = b
end

function BadgeIcon:ShowGouImg(b)
	if self._showGou == b then return end
	self._showGou = b

	if not self:IsIconValid() then return end

	self:SetGouTransVisible(self._showGou)
	self:ShowMask(self._showGou)
	self:ShowMask(self._showGou)
end

function BadgeIcon:ShowMask(bVisible)
	bVisible = bVisible and bVisible or false
	local gameObj = self._uiMaskTrans.gameObject
	if gameObj.activeSelf ~= bVisible then
		CS.ShowObject(gameObj, bVisible)
	end
end

function BadgeIcon:SetGouTransVisible(bVisible)
	self:ShowMask(self._showGou)
	bVisible = bVisible and bVisible or false
	local gameObj = self._uiGouTrans.gameObject
	if gameObj.activeSelf ~= bVisible then
		CS.ShowObject(gameObj, bVisible)
	end
end

function BadgeIcon:SetEquipIconGray()
	local b = self._showGou
	self:SetImageGray(self._uiIconBgTrans,b)
	self:SetImageGray(self._uiIconTrans,b)
end
function BadgeIcon:SetEmptyIconByPart(part)
	local iconPath = "public_item_bg_1"--self:GetEquipPartRef(part).emptyIcon
	if iconPath then
		self._displayShowIcon = iconPath
		self:SetIcon(self._displayShowIcon)
	end
end
-----------------------------------------------------------------
function BadgeIcon:SetPetData(info)
	self._refId = info.refId
	self._star = info.star
	local cfg = info.cfg or self:GetBadgeRef(self._refId)
	local quality = cfg.quality
	local qualityRef = self:GetItemQualityRef(quality)
	local itemColor ,iconBgPath= nil,nil
	if qualityRef then
		iconBgPath = qualityRef.iconBg
		local color = qualityRef.nameColor
		if color then
			itemColor = LUtil.ColorByHex(color)
		end
	end
	self._showLv = not not info
	self._lvTxtStr = info.level
	self._displayName = ccLngText(cfg.name)
	self._displayColor = itemColor

	self._displayStar = self._star or 0
	self._displayShowIcon = cfg.icon
	self._displayShowIconBg = iconBgPath
end

function BadgeIcon:SetData(refId, count)
	self._refId = refId
	local star = 0
	local ref = self:GetBadgeRef(refId)
	local iconPath = nil
	local iconBgPath = nil
	local itemName = nil
	local itemColor = nil
	self._num = count or 0
	local bRhombusIcon = self:IsRhombusIcon()
	self._badgeRef = ref
	if ref then
		iconPath = bRhombusIcon and ref.icon1 or ref.icon

		itemName = ccLngText(ref.name)
		local quality = ref.quality
		local qualityRef = self:GetItemQualityRef(quality)
		if qualityRef then
			--- 菱形的话使用这个 runeIconBg
			iconBgPath = bRhombusIcon and qualityRef.runeIconBg or qualityRef.iconBg

			local color = qualityRef.nameColor
			if color then
				itemColor = LUtil.ColorByHex(color)
			end
		end
		local info = gModelBadge:GetBadgeInfo(refId)
		self._showLv = not not info
		if info then
			self._lvTxtStr = info:GetBadgeLv()
			star = info:GetBadgeStar()
		end
		self._showNum = self._num>0
	else
		self._showNum = false
		self._showLv = false
		self._lvTxtStr = ""

		iconPath = bRhombusIcon and "heronew_fw_no" or "public_item_bg_add"
		iconBgPath = bRhombusIcon and "heronew_fw_1" or "public_item_bg_1"
	end

	self._displayName = itemName
	self._displayColor = itemColor

	self._displayStar = star or 0
	self._displayShowIcon = iconPath
	self._displayShowIconBg = iconBgPath

	self:UpdateNumData()
end
function BadgeIcon:SetRhombusIcon(bRhombusIcon,star)
	if not self._refId then return end
	local ref = self:GetBadgeRef(self._refId)
	local qualityRef
	if ref then
		qualityRef = self:GetItemQualityRef(ref.quality)
		local iconPath = bRhombusIcon and ref.icon1 or ref.icon
		self._displayShowIcon = iconPath
	end
	if qualityRef then
		self:SetRhombus(bRhombusIcon)
		local iconBgPath = bRhombusIcon and qualityRef.runeIconBg or qualityRef.iconBg
		self._displayShowIconBg = iconBgPath
	end
	if star then self._displayStar = star end

	self:UpdateIconBg()
end

function BadgeIcon:GetNameData()
	return self._displayName,self._displayColor
end


function BadgeIcon:UpdateLimitedImage()
	local minIconImg = self._displayLimited
	local badgeCfg= self:GetBadgeRef(self._refId)
	if badgeCfg and badgeCfg.sign>0 then
		self:SetCommonImg(self._uiLimited,minIconImg)
		if not self._uiLimited.gameObject.activeSelf then
			CS.ShowObject(self._uiLimited,true)
		end
	else
		if self._uiLimited.gameObject.activeSelf then
			CS.ShowObject(self._uiLimited,false)
		end
	end
end
-----------------------------------------------------------------
function BadgeIcon:GetBadgeRef(refId)

	return GameTable.BadgeRef[refId]
end



